586 | fun parseInlineMarkdown(text: String): androidx.compose.ui.text.AnnotatedString {
587 |     return buildAnnotatedString {
588 |         // This regex finds bold (**...**) and inline code (`...`)
589 |         val pattern = "(\\*\\*.*?\\*\\*|`.*?`)".toRegex()
590 |         var lastIndex = 0
591 |         
592 |         pattern.findAll(text).forEach { match ->
593 |             // Append text before the match
594 |             append(text.substring(lastIndex, match.range.first))
595 |             
596 |             val matchText = match.value
597 |             when {
598 |                 matchText.startsWith("**") && matchText.endsWith("**") -> {
599 |                     withStyle(style = SpanStyle(fontWeight = FontWeight.Bold, color = Color.White)) {
600 |                         append(matchText.removeSurrounding("**"))
601 |                     }
602 |                 }
603 |                 matchText.startsWith("`") && matchText.endsWith("`") -> {
604 |                     withStyle(style = SpanStyle(
605 |                         fontFamily = FontFamily.Monospace, 
606 |                         background = Color.Black.copy(alpha = 0.3f), 
607 |                         color = Color(0xFF80CBC4)
608 |                     )) {
609 |                         append(matchText.removeSurrounding("`"))
610 |                     }
611 |                 }
612 |                 else -> append(matchText)
613 |             }
614 |             lastIndex = match.range.last + 1
615 |         }
616 |         append(text.substring(lastIndex))
617 |     }
618 | }
